import time, math, hashlib
from dataclasses import dataclass
from binance.client import Client
from binance.exceptions import BinanceAPIException, BinanceRequestException

@dataclass
class Signal:
    symbol: str
    target_qty: float  # +long, -short, 0 flat
    ts: int

def cid_for(sig: Signal, bucket=5):
    b = sig.ts - (sig.ts % bucket)
    raw = f"{sig.symbol}|{b}|{sig.target_qty:.8f}"
    h = hashlib.sha256(raw.encode()).hexdigest()[:10]
    return f"bot_{sig.symbol}_{b}_{h}"

class BinanceQtySizer:
    def __init__(self, client: Client):
        self.client = client
        self._filters = {}  # symbol -> (stepSize, minQty)

    def _load_symbol(self, symbol: str):
        info = self.client.futures_exchange_info()
        for s in info["symbols"]:
            if s["symbol"] == symbol:
                lot = next(f for f in s["filters"] if f["filterType"] == "LOT_SIZE")
                step = float(lot["stepSize"])
                minq = float(lot["minQty"])
                self._filters[symbol] = (step, minq)
                return
        raise RuntimeError(f"Symbol not found in exchange info: {symbol}")

    def normalize_qty(self, symbol: str, qty: float) -> float:
        if symbol not in self._filters:
            self._load_symbol(symbol)
        step, minq = self._filters[symbol]
        # floor to step
        q = math.floor(qty / step) * step
        # avoid float junk
        q = float(f"{q:.12f}")
        if q < minq:
            return 0.0
        return q

class Executor:
    def __init__(self, client: Client, qty_sizer: BinanceQtySizer, dry_run=True, recv_window=5000):
        self.c = client
        self.sizer = qty_sizer
        self.dry_run = dry_run
        self.recv_window = recv_window

    def get_pos(self, symbol: str) -> float:
        # returns signed position amount
        positions = self.c.futures_position_information(symbol=symbol)
        # python-binance returns a list
        p = positions[0]
        return float(p["positionAmt"])

    def get_order_by_cid(self, symbol: str, cid: str):
        try:
            return self.c.futures_get_order(symbol=symbol, origClientOrderId=cid, recvWindow=self.recv_window)
        except BinanceAPIException:
            return None

    def market_to_target(self, sig: Signal, tolerance=0.0):
        symbol = sig.symbol
        target = sig.target_qty
        current = self.get_pos(symbol)
        delta = target - current

        if abs(delta) <= tolerance:
            return {"status": "NOOP", "symbol": symbol, "current": current, "target": target}

        side = Client.SIDE_BUY if delta > 0 else Client.SIDE_SELL
        qty = self.sizer.normalize_qty(symbol, abs(delta))
        if qty <= 0:
            return {"status": "NOOP_FILTERED", "symbol": symbol, "delta": delta}

