        if existing and existing.get("status") in ("NEW", "PARTIALLY_FILLED", "FILLED"):
            return {"status": "EXISTS", "symbol": symbol, "order": existing}

        reduce_only = (current > 0 and delta < 0) or (current < 0 and delta > 0)

        if self.dry_run:
            return {
                "status": "DRY_RUN",
                "symbol": symbol,
                "side": side,
                "qty": qty,
                "reduceOnly": reduce_only,
                "clientOrderId": cid,
                "current": current,
                "target": target,
            }

        return self.c.futures_create_order(
            symbol=symbol,
            side=side,
            type=Client.ORDER_TYPE_MARKET,
            quantity=qty,
            newClientOrderId=cid,
            reduceOnly=reduce_only,
            recvWindow=self.recv_window,
        )

    def execute_with_retries(self, sig: Signal, max_tries=6):
        delay = 0.4
        cid = cid_for(sig)
        for i in range(max_tries):
            try:
                return self.market_to_target(sig)
            except (BinanceRequestException, BinanceAPIException) as e:
                # did it place anyway? check by clientOrderId
